                <button type="submit" style={{ flex: 1, padding: '12px', background: 'var(--amber-500)', border: 'none', borderRadius: '8px', color: 'var(--slate-950)', fontFamily: 'var(--font-body)', fontSize: '14px', fontWeight: 600, cursor: 'pointer' }}>
