    52→const buildTrendData = (incidents: AnyRow[]) => {
    53→  const data = MONTHS.map(m => ({ month: m, incidents: 0, nearMisses: 0, toolboxTalks: 0 }));
    54→  incidents.forEach(inc => {
    55→    const d = new Date(String(inc.date ?? ''));
    56→    const idx = d.getMonth() - 8;
    57→    if (idx >= 0 && idx < 7) {
    58→      const t = String(inc.type ?? '');
    59→      if (['incident','first_aid','riddor'].includes(t)) data[idx].incidents++;
    60→      else if (['near-miss','near_miss'].includes(t)) data[idx].nearMisses++;
    61→      else if (['toolbox-talk','toolbox_talk'].includes(t)) data[idx].toolboxTalks++;
    62→    }
    63→  });
    64→  return data;
    65→};
    66→
    67→const buildRiskHeatmap = (incidents: AnyRow[], projects: AnyRow[]) => {
    68→  const risk: Record<string, any> = {};
    69→  projects.forEach(p => { risk[String(p.name ?? 'Unknown')] = { name: String(p.name ?? 'Unknown'), critical: 0, high: 0, medium: 0, low: 0, score: 0 }; });
    70→  incidents.forEach(inc => {
    71→    const proj = String(inc.project ?? 'Unknown');
    72→    const sev = String(inc.severity ?? 'low');
    73→    if (!risk[proj]) risk[proj] = { name: proj, critical: 0, high: 0, medium: 0, low: 0, score: 0 };
    74→    risk[proj][sev] = (risk[proj][sev] ?? 0) + 1;
    75→    risk[proj].score += {critical:4,high:3,medium:2,low:1}[sev] ?? 1;
    76→  });
    77→  return Object.values(risk).sort((a,b) => b.score - a.score).slice(0, 5);
    78→};
    79→
    80→const buildRootCauseData = (incidents: AnyRow[]) => {
    81→  const causes: Record<string, number> = {};
    82→  incidents.forEach(inc => { causes[String(inc.root_cause ?? 'unknown')] = (causes[String(inc.root_cause ?? 'unknown')] ?? 0) + 1; });
    83→  return Object.entries(causes).map(([name, value]) => ({ name, value }));
    84→};
