// Build monthly chart data from invoices
function buildChartData(invoices: AnyRow[]) {
  const now = new Date();
  const months: { month: string; revenue: number; profit: number }[] = [];
  for (let i = 5; i >= 0; i--) {
    const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
    months.push({ month: MONTH_ABBR[d.getMonth()], revenue: 0, profit: 0 });
  }
  invoices.filter(inv => inv.status === 'paid').forEach(inv => {
    const dateStr = String(inv.issueDate ?? inv.issue_date ?? '');
    if (!dateStr) return;
    const d = new Date(dateStr);
    const mIdx = months.findIndex(m => m.month === MONTH_ABBR[d.getMonth()] && d.getFullYear() === new Date().getFullYear());
    if (mIdx !== -1) {
      months[mIdx].revenue += Number(inv.amount ?? 0);
      months[mIdx].profit  += Number(inv.amount ?? 0) * 0.23;
    }
  });
  return months;
}

