/* ─── Design Token System ─────────────────────────────────────── */
:root {
  /* Slate foundation */
  --slate-950: #080b12;
  --slate-900: #0d1117;
  --slate-850: #111827;
  --slate-800: #161d2e;
  --slate-700: #1e293b;
  --slate-600: #283548;
  --slate-500: #3d4f66;
  --slate-400: #5a6a82;
