                {healthTrend === 'up' ? <TrendingUp style={{ width: '16px', height: '16px', color: 'var(--emerald-400)' }} /> : <TrendingDown style={{ width: '16px', height: '16px', color: 'var(--red-400)' }} />}
              </div>
