                        <HardHat style={{ width: '10px', height: '10px', color: 'var(--slate-500)' }} />
                        <span style={{ fontFamily: 'var(--font-mono)', fontSize: '9px', color: 'var(--slate-400)' }}>{workers} workers</span>
