          <div style={{ marginBottom: '16px' }}>
            <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '14px', fontWeight: 700, color: 'var(--slate-100)', letterSpacing: '-0.01em' }}>Quick Actions</h3>
