  border-color: var(--slate-700);
}
.btn-ghost:hover {
  background: var(--slate-800);
  color: var(--slate-100);
  border-color: var(--slate-600);
}

.input {
  width: 100%;
  background: var(--slate-800);
  border: 1px solid var(--slate-600);
  border-radius: 8px;
  padding: 10px 14px;
  font-family: var(--font-body);
