            })}
          </div>
        </div>

        {/* Resource Heatmap */}
        <ResourceHeatmap projects={projects} />
      </div>

      {/* ── Quick Actions + Safety Banner ─────────── */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
        {/* Quick Actions */}
        <div className="card card-grid animate-fade-up delay-5" style={{ padding: '20px' }}>
